noncompliant:
// Comma operator creates confusion and reduces readability
int result = a += 2, a + b;  // Noncompliant: What is the value of result?

// Error-prone in array subscripts
int matrix[10][10];
int value = matrix[i++, j++]; // Noncompliant: confusing with 2D array access

// Multiple assignments in one statement
int x, y, z;
x = 1, y = 2, z = 3; // Noncompliant: hard to read

// In function calls - very confusing
func(a = 1, b = 2, c = 3); // Noncompliant: looks like function parameters

compliant:
// Write each expression on its own line for clarity
a += 2;
int result = a + b; // Compliant: clear intention

// Proper 2D array access
int matrix[10][10];
i++;
j++;
int value = matrix[i][j]; // Compliant: clear array indexing

// Separate variable assignments
int x = 1; // Compliant
int y = 2; // Compliant
int z = 3; // Compliant

// Use proper initialization or separate statements
func(calculateA(), calculateB(), calculateC()); // Compliant: proper function call

// For loop is the only acceptable use case
for (int i = 0, j = 10; i < j; ++i, --j) { // Compliant: acceptable in for loop
    // process
}
